"""
overconfirmation.py - GV Overconfirmation v2.0 - Berechnung + Amend

Formel: ceil(ordered / bundle) * bundle
Save=_idJsp159, Back=_idJsp155
"""

import math

def calc_over(qty, bundle):
    if qty <= 0 or bundle <= 0:
        return qty, 0
    neu = int(math.ceil(qty / bundle) * bundle)
    return neu, neu - qty

async def fill_amend_and_save(page, bundle, do_save):
    result = await page.evaluate(f"""() => {{
        const eff = {bundle};
        const changes = [];
        const dataRows = document.querySelectorAll('tr.row_odd, tr.row_even');
        for (let ri = 0; ri < dataRows.length; ri++) {{
            const cells = dataRows[ri].querySelectorAll('td');
            const orderedText = (cells[6] || {{}}).innerText?.trim() || '0';
            const ordered = parseInt(orderedText) || 0;
            const committedInput = (cells[8] || {{}}).querySelector('input[type=\"text\"]');
            if (!committedInput || !committedInput.name.includes('_idJsp140')) continue;
            const committed = parseInt(committedInput.value) || 0;
            if (ordered <= 0) continue;
            const neu = Math.ceil(ordered / eff) * eff;
            const delta = neu - committed;
            if (delta !== 0) {{
                committedInput.value = neu.toString();
                committedInput.dispatchEvent(new Event('change', {{bubbles: true}}));
            }}
            changes.push({{ name: committedInput.name, ordered, old: committed, neu, delta }});
        }}
        return {{ changes }};
    }}""")
    any_changed = any(c.get("delta", 0) != 0 for c in result.get("changes", []))
    if do_save and any_changed:
        save_btn = page.locator('input[name="mainForm:_idJsp159"]')
        if await save_btn.count() > 0:
            await save_btn.click()
            await page.wait_for_load_state("networkidle")
    back_btn = page.locator('input[name="mainForm:_idJsp155"]')
    if await back_btn.count() > 0:
        await back_btn.click()
    else:
        await page.go_back()
    await page.wait_for_load_state("networkidle")
    return result

linkedin/connect.code:
// LinkedIn Auto-Connect fuer Multi-Account-VM
// - Nutzt persistenten Chrome-Profil (Cookie aus manuellem Login + 2FA)
// - Iteriert ueber Suchergebnisse oder mynetwork/grow Vorschlaege
// - Klickt "Vernetzen" + "Ohne Notiz senden", max MAX_CONNECTS pro Run
// - Schreibt workflow_runs Eintrag (R7)
//
// ENV:
//   LINKEDIN_PROFILE_DIR (req)  Profilverzeichnis, z.B. /home/exasync/profiles/michael
//   LINKEDIN_ACCOUNT      (req)  Account-Name fuer Logs, z.B. michael
//   MAX_CONNECTS          (opt)  Max Vernetzungen pro Run (default 5)
//   SEARCH_URL            (opt)  Start-URL (default: mynetwork/grow)
//   HEADLESS              (opt)  true/false (default false - sichtbar)
//   SUPABASE_URL,SUPABASE_ANON_KEY (opt) - fuer workflow_runs

import { chromium } from 'playwright';
import fs from 'node:fs';
import os from 'node:os';
import path from 'node:path';

const PROFILE_DIR = process.env.LINKEDIN_PROFILE_DIR;
const ACCOUNT     = process.env.LINKEDIN_ACCOUNT || 'unknown';
const MAX_CONNECTS = parseInt(process.env.MAX_CONNECTS || '5', 10);
const SEARCH_URL  = process.env.SEARCH_URL || 'https://www.linkedin.com/mynetwork/grow/';
const HEADLESS    = process.env.HEADLESS === 'true';
const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_KEY = process.env.SUPABASE_ANON_KEY;

if (!PROFILE_DIR) { console.error('ERROR: LINKEDIN_PROFILE_DIR fehlt'); process.exit(2); }

const TS = new Date().toISOString().replace(/[:.]/g, '-');
const LOG_DIR = '/home/exasync/logs';
const SHOT_DIR = '/home/exasync/testruns';
fs.mkdirSync(LOG_DIR, { recursive: true });
fs.mkdirSync(SHOT_DIR, { recursive: true });
const LOGFILE = `${LOG_DIR}/connect-${ACCOUNT}-${TS.slice(0,10)}.log`;

const log = (msg, level='INFO') => {
  const line = `[${new Date().toISOString()}] [${level}] ${msg}`;
  console.log(line);
  fs.appendFileSync(LOGFILE, line + '\n');
};

const sleep = ms => new Promise(r => setTimeout(r, ms));
const jitter = (min, max) => min + Math.floor(Math.random() * (max-min));

// Phase-Timing fuer Bottleneck-Analyse
const phaseEvents = []; // [{name, ms}]
const timed = async (name, fn) => {
  const t0 = Date.now();
  try { return await fn(); }
  finally { phaseEvents.push({ name, ms: Date.now() - t0 }); }
};
const aggregateTimings = () => {
  const byName = {};
  for (const e of phaseEvents) {
    byName[e.name] = byName[e.name] || { n: 0, total: 0, min: Infinity, max: 0, samples: [] };
    const x = byName[e.name];
    x.n++; x.total += e.ms; x.min = Math.min(x.min, e.ms); x.max = Math.max(x.max, e.ms);
    x.samples.push(e.ms);
  }
  for (const k in byName) {
    const x = byName[k];
    x.mean = Math.round(x.total / x.n);
    x.samples.sort((a,b)=>a-b);
    x.p50 = x.samples[Math.floor(x.samples.length*0.5)];
    x.p95 = x.samples[Math.floor(x.samples.length*0.95)] || x.max;
    delete x.samples; // sparen fuer JSON
  }
  return byName;
};

const startTime = new Date();
let status = 'success';
let errorDetails = null;
let connectsSent = 0;
let attemptedClicks = 0;
let stopReason = '';
let finalUrl = '';
let loggedIn = false;
// Vorab-Deklaration fuer metrics-Block (Sets werden im try-Block befuellt)
let verifiedAria, failedAria;
let bannerHits = 0;

let browser;
try {
  log(`Auto-Connect startet | account=${ACCOUNT} max=${MAX_CONNECTS} url=${SEARCH_URL}`);
  log(`Profile: ${PROFILE_DIR}`);

  browser = await timed('browser_launch', () => chromium.launchPersistentContext(PROFILE_DIR, {
    channel: 'chrome',
    headless: HEADLESS,
    viewport: { width: 1280, height: 900 },
    args: ['--no-first-run', '--no-default-browser-check']
  }));

  const page = browser.pages()[0] || await browser.newPage();

  // 1. Login-Check via /feed/
  log('Pruefe Login via /feed/');
  await timed('login_check_navigate', () => page.goto('https://www.linkedin.com/feed/', { waitUntil: 'domcontentloaded', timeout: 30000 }));
  await sleep(2500);
  finalUrl = page.url();
  loggedIn = finalUrl.includes('/feed') && !finalUrl.includes('/login') && !finalUrl.includes('/checkpoint');

  if (!loggedIn) {
    stopReason = `not_logged_in (url=${finalUrl})`;
    status = 'error';
    errorDetails = stopReason;
    log(`Nicht eingeloggt - stop. URL=${finalUrl}`, 'ERROR');
    await page.screenshot({ path: `${SHOT_DIR}/${TS}-${ACCOUNT}-notlogged.png` }).catch(()=>{});
    throw new Error(stopReason);
  }
  log(`Eingeloggt (url=${finalUrl})`, 'OK');

  // 2. Navigation zur Such-/Vorschlaegeseite
  log(`Navigiere zu Zielseite: ${SEARCH_URL}`);
  await timed('target_navigate', () => page.goto(SEARCH_URL, { waitUntil: 'domcontentloaded', timeout: 30000 }));
  await sleep(jitter(2500, 4000));
  finalUrl = page.url();
  log(`URL nach Navigate: ${finalUrl}`);
  await page.screenshot({ path: `${SHOT_DIR}/${TS}-${ACCOUNT}-page.png` }).catch(()=>{});

  // 2b. Auf mynetwork/grow/: "Alle anzeigen" neben "Personen aus Aktivitaeten" klicken (auto-connect.md V1.2)
  if (/mynetwork\/grow/.test(finalUrl)) {
    log('mynetwork/grow erkannt — klicke "Alle anzeigen" bei Aktivitaeten-Vorschlaegen');
    const clicked = await timed('alle_anzeigen_click', () => page.evaluate(() => {
      const candidates = Array.from(document.querySelectorAll('a[aria-label], button[aria-label]'));
      const target = candidates.find(el => /Aktivit[aä]ten/i.test(el.getAttribute('aria-label') || ''));
      if (target) { target.click(); return target.getAttribute('aria-label'); }
      return null;
    }));
    if (clicked) {
      log(`"Alle anzeigen" geklickt: ${clicked}`, 'OK');
      await sleep(jitter(2500, 4000));
      finalUrl = page.url();
      log(`URL nach Alle-Anzeigen: ${finalUrl}`);
      await page.screenshot({ path: `${SHOT_DIR}/${TS}-${ACCOUNT}-cohort.png` }).catch(()=>{});
    } else {
      log('Kein Aktivitaeten-Alle-Anzeigen gefunden — nutze direkte Vorschlaegeseite', 'WARN');
    }
  }

  // Helper: erkennt LinkedIn-Blocker-Banner (Wochenlimit, Sicherheits-Warning, etc.)
  const checkBlockingBanner = async () => {
    return await page.evaluate(() => {
      // (1) Sichtbare role=alert / aria-live Notifications
      const alerts = Array.from(document.querySelectorAll('[role="alert"], [aria-live="assertive"]'));
      for (const a of alerts) {
        if (!a.offsetParent) continue;
        const txt = (a.textContent || '').trim();
        if (txt.length > 0 && txt.length < 600) {
          return { found: true, source: 'role=alert', text: txt.slice(0, 250) };
        }
      }
      // (2) Sichtbare LinkedIn Inline-Feedback Error-Komponenten
      const errBlocks = Array.from(document.querySelectorAll('.artdeco-inline-feedback--error, .artdeco-toast-item--error, [data-test-banner-type="error"]'));
      for (const e of errBlocks) {
        if (!e.offsetParent) continue;
        const txt = (e.textContent || '').trim();
        if (txt.length > 0) return { found: true, source: 'inline-feedback-error', text: txt.slice(0, 250) };
      }
      // (3) Sichtbare Error/Warning Icons + ihr umgebender Text
      const errIcons = Array.from(document.querySelectorAll('svg[data-test-icon*="error"], svg[data-test-icon*="warning"], li-icon[type*="error"], li-icon[type*="warning"]'));
      for (const e of errIcons) {
        if (!e.offsetParent) continue;
        const wrap = e.closest('[role], section, div, span');
        const txt = (wrap?.textContent || '').trim();
        if (txt.length > 5 && txt.length < 400) return { found: true, source: 'error-icon', text: txt.slice(0, 250) };
      }
      // (4) Body-Text-Pattern fuer harte Limits / Restrictions
      const bodyTxt = document.body.innerText || '';
      const patterns = [
        /Wochenlimit\s+(?:fast\s+)?erreicht/i,
        /weekly\s+invitation\s+limit/i,
        /Sie haben Ihr w[oö]chentliches Limit/i,
        /Sie\s+haben\s+(?:zu\s+viele|in\s+kurzer\s+Zeit\s+zu\s+viele)/i,
        /You.*(?:weekly|invitation).*limit/i,
        /vor[uü]bergehend\s+nicht\s+m[oö]glich/i,
        /Anmeldung\s+vor[uü]bergehend\s+gesperrt/i,
        /This\s+account\s+is\s+(?:restricted|blocked)/i,
        /try\s+again\s+(?:in\s+a\s+few|later)/i,
        /Ihr Konto wurde eingeschr[aä]nkt/i
      ];
      for (const re of patterns) {
        const m = bodyTxt.match(re);
        if (m) return { found: true, source: 'text-pattern', pattern: re.source, text: m[0] };
      }
      return { found: false };
    });
  };

  // 3. Connect-Loop mit Person-Tracking + Status-Verifikation + Banner-Stop
  log(`Starte Connect-Loop (max ${MAX_CONNECTS})`);
  const attemptedAria = new Set();   // bereits geklickte Personen (per aria-label)
  verifiedAria = new Set();          // Personen, deren Button auf "Ausstehend" gewechselt hat
  failedAria = new Set();            // Personen, die nicht verifiziert werden konnten
  let consecutiveEmpty = 0;

  while (connectsSent < MAX_CONNECTS) {
    // (a) Banner-Check VOR jedem neuen Klick — wenn Limit/Warning sichtbar, sofort stoppen
    const preBanner = await timed('banner_check', () => checkBlockingBanner());
    if (preBanner.found) {
      bannerHits++;
      stopReason = `blocking_banner: [${preBanner.source}] ${preBanner.text}`;
      log(`STOP: Blocker-Banner erkannt (${preBanner.source}): "${preBanner.text}"`, 'WARN');
      await page.screenshot({ path: `${SHOT_DIR}/${TS}-${ACCOUNT}-banner.png`, fullPage: true }).catch(()=>{});
      break;
    }

    // Liste ALLER sichtbaren Vernetzen-Buttons mit ihrem aria-label
    const candidates = await timed('button_search', () => page.evaluate(() => {
      return Array.from(document.querySelectorAll('button'))
        .filter(b => {
          if (!b.offsetParent) return false;
          const txt = (b.textContent || '').trim();
          const aria = b.getAttribute('aria-label') || '';
          return txt === 'Vernetzen' || txt === 'Connect' || aria.includes('als Kontakt einladen') || aria.toLowerCase().includes('invite');
        })
        .map(b => b.getAttribute('aria-label') || '');
    }));

    // Filter raus die wir schon versucht haben
    const fresh = candidates.filter(a => !attemptedAria.has(a));
    log(`Buttons sichtbar: ${candidates.length} | davon frisch: ${fresh.length}`);

    if (fresh.length === 0) {
      consecutiveEmpty++;
      if (consecutiveEmpty >= 3) {
        stopReason = 'no_more_fresh_targets';
        log('3x in Folge keine frischen Personen - stop', 'WARN');
        break;
      }
      await timed('scroll_load_more', () => page.evaluate(() => window.scrollBy(0, 600)));
      await sleep(jitter(1500, 2500));
      continue;
    }
    consecutiveEmpty = 0;

    const targetAria = fresh[0];
    attemptedAria.add(targetAria);
    attemptedClicks++;

    // Klick auf genau diesen Button (per aria-label match)
    const clicked = await timed('button_click', () => page.evaluate((aria) => {
      const btn = Array.from(document.querySelectorAll('button')).find(b =>
        b.offsetParent && b.getAttribute('aria-label') === aria
      );
      if (!btn) return false;
      btn.scrollIntoView({ block: 'center' });
      btn.click();
      return true;
    }, targetAria));
    if (!clicked) {
      log(`Klick #${attemptedClicks}: Button verschwunden vor Klick (${targetAria})`, 'WARN');
      failedAria.add(targetAria);
      continue;
    }
    log(`Klick #${attemptedClicks}: ${targetAria}`, 'INFO');

    // Modal abwarten + "Ohne Notiz senden"
    const modalWaitMs = jitter(800, 1400);
    await sleep(modalWaitMs);
    phaseEvents.push({ name: 'modal_wait_sleep', ms: modalWaitMs });

    const modalHandled = await timed('modal_handle', () => page.evaluate(() => {
      const sendNoNote = Array.from(document.querySelectorAll('button')).find(b => {
        const t = (b.textContent || '').trim();
        return t === 'Ohne Notiz senden' || t === 'Send without a note' || t === 'Senden' || t === 'Send now';
      });
      if (sendNoNote) { sendNoNote.click(); return 'sent_without_note'; }
      const limitText = document.body.innerText || '';
      if (/Wochenlimit|weekly limit|invitation limit|too many/i.test(limitText)) return 'weekly_limit';
      return 'no_modal';
    }));

    if (modalHandled === 'weekly_limit') {
      stopReason = 'weekly_limit';
      log('Wochenlimit erreicht - stop', 'WARN');
      await page.screenshot({ path: `${SHOT_DIR}/${TS}-${ACCOUNT}-limit.png` }).catch(()=>{});
      break;
    }
    if (modalHandled !== 'sent_without_note') {
      log(`Kein "Ohne Notiz senden" Modal (${modalHandled}) - skip Person`, 'WARN');
      failedAria.add(targetAria);
      continue;
    }

    // (b) Banner-Check NACH dem Send — LinkedIn zeigt Limit-Toast oft erst nach Submit
    await sleep(800);
    const postBanner = await timed('banner_check', () => checkBlockingBanner());
    if (postBanner.found) {
      bannerHits++;
      stopReason = `blocking_banner_after_send: [${postBanner.source}] ${postBanner.text}`;
      log(`STOP nach Send: Blocker-Banner (${postBanner.source}): "${postBanner.text}"`, 'WARN');
      await page.screenshot({ path: `${SHOT_DIR}/${TS}-${ACCOUNT}-banner-postsend.png`, fullPage: true }).catch(()=>{});
      // Diesen Send NICHT als verified zaehlen — LinkedIn kann ihn verworfen haben
      failedAria.add(targetAria);
      break;
    }

    // KRITISCH: Warte bis Button auf "Ausstehend"/"Pending" wechselt = echte Bestaetigung
    const verified = await timed('verify_pending', () => page.waitForFunction((aria) => {
      // Button mit gleichem aria-label suchen
      const btn = Array.from(document.querySelectorAll('button')).find(b => b.getAttribute('aria-label') === aria);
      if (!btn) return true; // Button verschwunden = wahrscheinlich erfolgreich
      const txt = (btn.textContent || '').trim();
      return txt === 'Ausstehend' || txt === 'Pending';
    }, targetAria, { timeout: 5000 }).then(() => true).catch(() => false));

    if (verified) {
      connectsSent++;
      verifiedAria.add(targetAria);
      log(`Connect #${connectsSent} VERIFIZIERT (Ausstehend): ${targetAria}`, 'OK');
    } else {
      failedAria.add(targetAria);
      log(`Connect NICHT verifiziert nach 5s: ${targetAria}`, 'WARN');
      await page.screenshot({ path: `${SHOT_DIR}/${TS}-${ACCOUNT}-unverified-${attemptedClicks}.png` }).catch(()=>{});
    }

    const interMs = jitter(2000, 3500);
    await sleep(interMs);
    phaseEvents.push({ name: 'inter_click_sleep', ms: interMs });

    // Nach jedem 4. Klick scrollen
    if (attemptedClicks % 4 === 0) {
      await timed('scroll_after_4', () => page.evaluate(() => window.scrollBy(0, 500)));
      await sleep(jitter(1500, 2500));
    }
  }

  if (!stopReason) stopReason = `max_reached (${connectsSent}/${MAX_CONNECTS})`;

  await page.screenshot({ path: `${SHOT_DIR}/${TS}-${ACCOUNT}-final.png` }).catch(()=>{});
  log(`Loop fertig: verified=${connectsSent}, attempts=${attemptedClicks}, failed=${failedAria.size}, stop=${stopReason}`, 'OK');
  if (verifiedAria.size > 0) log(`Verifiziert: ${[...verifiedAria].slice(0,5).join(' | ')}${verifiedAria.size>5?' ...':''}`);

} catch (err) {
  status = 'error';
  errorDetails = (errorDetails || '') + ' | ' + err.message;
  log(`FEHLER: ${err.message}`, 'ERROR');
  log(err.stack, 'ERROR');
} finally {
  if (browser) {
    try { await browser.close(); log('Chrome geschlossen'); } catch(e) { log(`close-err: ${e.message}`, 'WARN'); }
  }
}

// Phase-Aggregat fuer Bottleneck-Analyse
const timings = aggregateTimings();
log('=== BOTTLENECK-ANALYSE (alle Werte in ms) ===');
log(`${'Phase'.padEnd(24)} ${'n'.padStart(4)} ${'mean'.padStart(7)} ${'p50'.padStart(7)} ${'p95'.padStart(7)} ${'min'.padStart(7)} ${'max'.padStart(7)} ${'total'.padStart(8)}`);
const sortedPhases = Object.entries(timings).sort((a,b) => b[1].total - a[1].total);
for (const [name, t] of sortedPhases) {
  log(`${name.padEnd(24)} ${String(t.n).padStart(4)} ${String(t.mean).padStart(7)} ${String(t.p50).padStart(7)} ${String(t.p95).padStart(7)} ${String(t.min).padStart(7)} ${String(t.max).padStart(7)} ${String(t.total).padStart(8)}`);
}
const totalMs = Date.now() - startTime.getTime();
log(`GESAMT-RUN: ${totalMs} ms = ${(totalMs/1000).toFixed(1)}s = ${(totalMs/60000).toFixed(2)}min`);
if (connectsSent > 0) log(`PRO CONNECT (mean): ${Math.round(totalMs/connectsSent)} ms = ${(totalMs/connectsSent/1000).toFixed(1)}s`);

// workflow_runs (R7)
if (SUPABASE_URL && SUPABASE_KEY) {
  try {
    const res = await fetch(`${SUPABASE_URL}/rest/v1/workflow_runs`, {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        workflow_id: 'linkedin-auto-connect',
        status,
        vm: os.hostname(),
        started_at: startTime.toISOString(),
        finished_at: new Date().toISOString(),
        metrics: {
          account: ACCOUNT,
          logged_in: loggedIn,
          connects_verified: connectsSent,
          attempts: attemptedClicks,
          failed_count: failedAria ? failedAria.size : 0,
          verified_persons: verifiedAria ? [...verifiedAria].slice(0, 50) : [],
          banner_hits: typeof bannerHits === 'number' ? bannerHits : 0,
          max_connects: MAX_CONNECTS,
          stop_reason: stopReason,
          search_url: SEARCH_URL,
          duration_ms: totalMs,
          ms_per_connect: connectsSent > 0 ? Math.round(totalMs/connectsSent) : null,
          phase_timings: timings
        },
        trigger: 'manual',
        agent_id: ACCOUNT,
        error_message: errorDetails
      })
    });
    log(`workflow_runs: HTTP ${res.status}`, res.ok ? 'OK' : 'WARN');
  } catch (e) {
    log(`workflow_runs Fehler: ${e.message}`, 'WARN');
  }
}

log(`FERTIG | account=${ACCOUNT} status=${status} connects=${connectsSent} stop=${stopReason}`);
process.exit(status === 'error' ? 1 : 0);

